script:
app.beginUndoGroup("Ease Opacity and Position Keyframes");
function easeArray(prop, speed, influence) {
  var n = prop.isSpatial ? 1 : (prop.value instanceof Array ? prop.value.length : 1);
  var arr = [];
  for (var i = 0; i < n; i++) arr.push(new KeyframeEase(speed, influence));
  return arr;
}
var comp = app.project.activeItem;
if (!(comp instanceof CompItem)) {
  throw new Error("Open a composition first.");
}
var layer = comp.layers.addSolid([1, 0.45, 0.1], "Eased Layer", comp.width, comp.height, comp.pixelAspect, comp.duration);
var transform = layer.property("ADBE Transform Group");
var opacity = transform.property("ADBE Opacity");
var position = transform.property("ADBE Position");
opacity.setValueAtTime(0, 0);
opacity.setValueAtTime(1, 100);
position.setValueAtTime(0, [comp.width / 2 - 200, comp.height / 2]);
position.setValueAtTime(1, [comp.width / 2, comp.height / 2]);
var opacityEaseIn = easeArray(opacity, 0, 80);
var opacityEaseOut = easeArray(opacity, 0, 80);
var positionEaseIn = easeArray(position, 0, 80);
var positionEaseOut = easeArray(position, 0, 80);
opacity.setTemporalEaseAtKey(1, opacityEaseIn, opacityEaseOut);
opacity.setTemporalEaseAtKey(2, opacityEaseIn, opacityEaseOut);
position.setTemporalEaseAtKey(1, positionEaseIn, positionEaseOut);
position.setTemporalEaseAtKey(2, positionEaseIn, positionEaseOut);
app.endUndoGroup();
